// className nümunəsi
const div = document.querySelector('#myDiv');
console.log('İlkin siniflər:', div.className); // Sinifləri konsola yazdırır
div.className = 'highlight active'; // Sinifləri dəyişdirir

// classList nümunəsi
const div = document.querySelector('#myDiv');
div.classList.add('highlight'); // highlight sinfini əlavə edir
console.log('highlight var mı?', div.classList.contains('highlight')); // true
div.classList.toggle('active'); // active sinfini əlavə edir və ya silir
div.classList.remove('highlight'); // highlight sinfini silir

// Hadisə ilə sinif dəyişdirmə nümunəsi
const button = document.querySelector('#myButton');
const div = document.querySelector('#myDiv');
button.addEventListener('click', () => {
  div.classList.toggle('highlight'); // highlight sinfini əlavə edir/silir
  console.log('highlight sinfi dəyişdirildi:', div.classList.contains('highlight'));
});

// Səhvə yol açan nümunə
const element = document.querySelector('#nonExistent');
element.className = 'highlight'; // TypeError: Cannot set property 'className' of null

// Düzgün yol
const safeElement = document.querySelector('#nonExistent');
if (safeElement) {
  safeElement.className = 'highlight';
} else {
  console.log('Element tapılmadı');
}

// className example
const div = document.querySelector('#myDiv');
console.log('Initial classes:', div.className); // Logs classes
div.className = 'highlight active'; // Replaces classes

// classList example
const div = document.querySelector('#myDiv');
div.classList.add('highlight'); // Adds highlight class
console.log('Has highlight?', div.classList.contains('highlight')); // true
div.classList.toggle('active'); // Toggles active class
div.classList.remove('highlight'); // Removes highlight class

// Event-driven class change example
const button = document.querySelector('#myButton');
const div = document.querySelector('#myDiv');
button.addEventListener('click', () => {
  div.classList.toggle('highlight'); // Toggles highlight class
  console.log('Highlight toggled:', div.classList.contains('highlight'));
});

// Error-prone example
const element = document.querySelector('#nonExistent');
element.className = 'highlight'; // TypeError: Cannot set property 'className' of null

// Correct approach
const safeElement = document.querySelector('#nonExistent');
if (safeElement) {
  safeElement.className = 'highlight';
} else {
  console.log('Element not found');
}

// Пример className
const div = document.querySelector('#myDiv');
console.log('Исходные классы:', div.className); // Выводит классы
div.className = 'highlight active'; // Заменяет классы

// Пример classList
const div = document.querySelector('#myDiv');
div.classList.add('highlight'); // Добавляет класс highlight
console.log('Есть highlight?', div.classList.contains('highlight')); // true
div.classList.toggle('active'); // Переключает класс active
div.classList.remove('highlight'); // Удаляет класс highlight

// Пример изменения класса с событием
const button = document.querySelector('#myButton');
const div = document.querySelector('#myDiv');
button.addEventListener('click', () => {
  div.classList.toggle('highlight'); // Переключает класс highlight
  console.log('Класс highlight переключен:', div.classList.contains('highlight'));
});

// Пример с ошибкой
const element = document.querySelector('#nonExistent');
element.className = 'highlight'; // TypeError: Cannot set property 'className' of null

// Правильный подход
const safeElement = document.querySelector('#nonExistent');
if (safeElement) {
  safeElement.className = 'highlight';
} else {
  console.log('Элемент не найден');
}
